#!/usr/bin/env python3
import requests

def check_endpoint(url, name):
    try:
        response = requests.get(url, timeout=10)
        print(f'{name}: Status {response.status_code}')
        if response.status_code == 200:
            print(f'  ✓ Healthy - Response: {response.text.strip()[:200]}')
        else:
            print(f'  ✗ Unhealthy')
        return response.status_code
    except requests.exceptions.ConnectionError:
        print(f'{name}: Connection Error - Unable to connect to the server')
        return None
    except requests.exceptions.Timeout:
        print(f'{name}: Timeout Error - Request timed out')
        return None
    except Exception as e:
        print(f'{name}: Error {e}')
        return None

def main():
    # Test first endpoint
    url1 = "http://localhost:3003/checkConnectivity?variant=2"
    check_endpoint(url1, "Endpoint 1")

